/**
 * MedX spinner runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Loading spinners for async operations: wallet connect, blockchain sync, CSV export.
 */
const SPINNER_SIZES = Object.freeze({
  xs: { size: 12, stroke: 2 },
  sm: { size: 16, stroke: 2 },
  md: { size: 24, stroke: 3 },
  lg: { size: 32, stroke: 3 },
  xl: { size: 48, stroke: 4 },
});

const SPINNER_OPERATIONS = Object.freeze({
  walletConnect: { label: "Connecting wallet...", timeoutMs: 30000 },
  blockchainSync: { label: "Syncing blockchain records...", timeoutMs: 120000 },
  csvExport: { label: "Exporting inventory CSV...", timeoutMs: 60000 },
  batchReceive: { label: "Processing batch receive...", timeoutMs: 45000 },
  authRefresh: { label: "Refreshing session...", timeoutMs: 15000 },
});

const activeSpinners = new Map();
let spinnerIdSeq = 0;

function createSpinner(config) {
  const id = config.id ?? `medx-spinner-${++spinnerIdSeq}`;
  const operation = config.operation ? SPINNER_OPERATIONS[config.operation] : null;
  const size = config.size ?? "md";
  const spinner = {
    id,
    operation: config.operation ?? null,
    label: config.label ?? operation?.label ?? "Loading...",
    size,
    sizeStyles: SPINNER_SIZES[size] ?? SPINNER_SIZES.md,
    visible: true,
    startedAt: Date.now(),
    timeoutMs: config.timeoutMs ?? operation?.timeoutMs ?? 60000,
    timeoutHandle: null,
    onTimeout: typeof config.onTimeout === "function" ? config.onTimeout : null,
  };
  activeSpinners.set(id, spinner);
  scheduleSpinnerTimeout(id);
  return spinner;
}

function scheduleSpinnerTimeout(id) {
  const spinner = activeSpinners.get(id);
  if (!spinner) return;
  spinner.timeoutHandle = setTimeout(() => {
    if (activeSpinners.has(id)) {
      spinner.timedOut = true;
      if (spinner.onTimeout) spinner.onTimeout(spinner);
      stopSpinner(id, "timeout");
    }
  }, spinner.timeoutMs);
}

function stopSpinner(id, reason = "complete") {
  const spinner = activeSpinners.get(id);
  if (!spinner) return false;
  clearTimeout(spinner.timeoutHandle);
  spinner.visible = false;
  spinner.stoppedAt = Date.now();
  spinner.durationMs = spinner.stoppedAt - spinner.startedAt;
  spinner.stopReason = reason;
  activeSpinners.delete(id);
  return spinner;
}

function getActiveSpinnerCount() {
  return activeSpinners.size;
}

function stopAllSpinners(reason = "cancel") {
  const ids = Array.from(activeSpinners.keys());
  return ids.map((id) => stopSpinner(id, reason));
}

async function runMedxSpinner() {
  console.log("[medx:ui:spinner] runtime initialized");
  console.log(`[medx:ui:spinner] sizes=${Object.keys(SPINNER_SIZES).length} operations=${Object.keys(SPINNER_OPERATIONS).length}`);

  const wallet = createSpinner({ operation: "walletConnect", size: "lg" });
  const export_ = createSpinner({ operation: "csvExport", size: "sm" });
  const sync = createSpinner({ operation: "blockchainSync", size: "md" });

  await new Promise((resolve) => setTimeout(resolve, 80));

  const walletResult = stopSpinner(wallet.id, "complete");
  stopSpinner(export_.id, "complete");

  console.log(`[medx:ui:spinner] active=${getActiveSpinnerCount()}`);
  console.log(`[medx:ui:spinner] walletDurationMs=${walletResult?.durationMs}`);
  console.log("[medx:ui:spinner] sync still running=", activeSpinners.has(sync.id));
  stopAllSpinners("bootstrap-cleanup");
  console.log("[medx:ui:spinner] bootstrap complete");
}

module.exports = runMedxSpinner;
